from fastapi import FastAPI
from .router_tasks import router as tasks_router

app = FastAPI(title='Hermes Gateway', version='1.0.0')
app.include_router(tasks_router, prefix='/task', tags=['tasks'])

@app.get('/health')
def health():
    return {'status': 'ok', 'service': 'hermes-gateway', 'version': '1.0.0'}

@app.post('/context')
def context_proxy(query: str, budget_tokens: int = 1500):
    import urllib.request, json
    req = urllib.request.Request(
        'http://localhost:8643/v1/rag',
        data=json.dumps({'query': query}).encode(),
        headers={'Content-Type': 'application/json'}
    )
    with urllib.request.urlopen(req, timeout=30) as resp:
        return json.loads(resp.read().decode())

if __name__ == '__main__':
    import uvicorn
    uvicorn.run(app, host='0.0.0.0', port=8642)
